import jakarta.servlet.http.HttpServletResponse;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.io.*;
import org.springframework.mock.web.MockHttpServletResponse;

@Component
public class RateLimitResponseBuilder {
    private static final int LIMIT = 100;
    private static final int RETRY_AFTER_SECONDS = 60;

    public void sendRateLimitExceeded(HttpServletResponse response) throws IOException {
        response.setStatus(429);  // 429 Too Many Requests
        response.setContentType("application/json");

        // Standard rate limit headers (RFC 6585 + draft RateLimit spec):
        response.setHeader("X-RateLimit-Limit", String.valueOf(LIMIT));
        response.setHeader("X-RateLimit-Remaining", "0");
        response.setHeader("Retry-After", String.valueOf(RETRY_AFTER_SECONDS));
        response.setHeader("X-RateLimit-Reset",
            String.valueOf(System.currentTimeMillis() / 1000 + RETRY_AFTER_SECONDS));

        response.getWriter().write(
            "{\"error\":\"rate_limit_exceeded\",\"retryAfter\":" + RETRY_AFTER_SECONDS + "," +
            "\"message\":\"Rate limit exceeded. Please retry after 60 seconds.\"}");
    }
}

@SpringBootTest
class RateLimitResponseTest {
    @Autowired RateLimitResponseBuilder builder;

    @Test void rateLimitResponse_correctHeaders() throws IOException {
        MockHttpServletResponse response = new MockHttpServletResponse();
        builder.sendRateLimitExceeded(response);

        assertEquals(429, response.getStatus());
        assertEquals("100", response.getHeader("X-RateLimit-Limit"));
        assertEquals("0", response.getHeader("X-RateLimit-Remaining"));
        assertEquals("60", response.getHeader("Retry-After"));
        assertTrue(response.getContentAsString().contains("rate_limit_exceeded"));
    }
}

