import org.springframework.web.filter.OncePerRequestFilter;
import jakarta.servlet.*;
import jakarta.servlet.http.*;
import org.springframework.stereotype.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.io.*;
import io.github.bucket4j.*;
import com.github.benmanes.caffeine.cache.*;
import java.util.concurrent.TimeUnit;
import java.time.Duration;

@Component
public class PaymentRateLimitFilter extends OncePerRequestFilter {
    private final LoadingCache<String, Bucket> buckets = Caffeine.newBuilder()
        .expireAfterAccess(1, TimeUnit.HOURS)
        .build(key -> Bucket.builder()
            .addLimit(Bandwidth.classic(100, Refill.greedy(100, Duration.ofMinutes(1))))
            .build());

    @Override
    protected void doFilterInternal(HttpServletRequest req, HttpServletResponse res,
                                    FilterChain chain) throws IOException, ServletException {
        String key = extractKey(req);
        Bucket bucket = buckets.get(key);

        if (bucket.tryConsume(1)) {
            // Allowed: add remaining tokens header
            res.setHeader("X-RateLimit-Remaining", String.valueOf(bucket.getAvailableTokens()));
            chain.doFilter(req, res);
        } else {
            // Rate limited:
            res.setStatus(429);
            res.setContentType("application/json");
            res.setHeader("X-RateLimit-Limit", "100");
            res.setHeader("X-RateLimit-Remaining", "0");
            res.setHeader("Retry-After", "60");
            res.getWriter().write("{\"error\":\"rate_limit_exceeded\",\"retryAfter\":60}");
        }
    }

    private String extractKey(HttpServletRequest req) {
        // Prefer JWT sub (merchant ID) over IP:
        String auth = req.getHeader("Authorization");
        if (auth != null && auth.startsWith("Bearer ")) {
            // In production: parse JWT and extract 'sub' or 'merchant_id' claim
            // For simplicity: use the token itself as key (not ideal for prod)
            return "jwt:" + auth.substring(7, Math.min(20, auth.length()));
        }
        // Fallback: rate limit by IP (for unauthenticated endpoints)
        String ip = req.getHeader("X-Forwarded-For");
        return "ip:" + (ip != null ? ip.split(",")[0].trim() : req.getRemoteAddr());
    }
}

@SpringBootTest
class RateLimitFilterTest {
    @Autowired PaymentRateLimitFilter filter;
    @Test void filter_instantiates() { assertNotNull(filter); }
}

