import java.util.concurrent.TimeUnit;

@Service
public class TieredRateLimiter {
    enum Plan { STANDARD, PREMIUM, ENTERPRISE }

    private static final Map<Plan, Integer> LIMITS = Map.of(
        Plan.STANDARD, 100,
        Plan.PREMIUM, 500,
        Plan.ENTERPRISE, 2000
    );

    private final LoadingCache<String, Bucket> buckets = Caffeine.newBuilder()
        .expireAfterAccess(1, TimeUnit.HOURS)
        .build(key -> newBucket(Plan.STANDARD));  // default

    public Bucket getBucket(String merchantId, Plan plan) {
        String key = merchantId + ":" + plan.name();
        return Caffeine.newBuilder()
            .expireAfterAccess(1, TimeUnit.HOURS)
            .<String,Bucket>build(k -> newBucket(plan))
            .get(key);
    }

    private Bucket newBucket(Plan plan) {
        int limit = LIMITS.get(plan);
        return Bucket.builder()
            .addLimit(Bandwidth.classic(limit, Refill.greedy(limit, Duration.ofMinutes(1))))
            .build();
    }

    public boolean isAllowed(String merchantId, Plan plan) {
        return getBucket(merchantId, plan).tryConsume(1);
    }

    public long getLimit(Plan plan) { return LIMITS.get(plan); }
}

@SpringBootTest
class TieredRateLimiterTest {
    @Autowired TieredRateLimiter limiter;

    @Test void standard_limit() { assertEquals(100, limiter.getLimit(TieredRateLimiter.Plan.STANDARD)); }
    @Test void premium_limit()  { assertEquals(500, limiter.getLimit(TieredRateLimiter.Plan.PREMIUM)); }
    @Test void enterprise_limit(){ assertEquals(2000, limiter.getLimit(TieredRateLimiter.Plan.ENTERPRISE)); }
}

