@Component
public class ApiKeyAuthFilter extends OncePerRequestFilter {
    // In production: store in DB or Redis (hashed)
    private static final Map<String, String> API_KEYS = Map.of(
        "rzp_live_flipkart_abc123", "MRC-FLIPKART-001",
        "rzp_live_zomato_def456",   "MRC-ZOMATO-002",
        "rzp_live_hdfc_ghi789",    "MRC-HDFC-003"
    );

    public static final String MERCHANT_ID_ATTR = "merchantId";

    @Override
    protected void doFilterInternal(HttpServletRequest req, HttpServletResponse res,
                                    FilterChain chain) throws IOException, ServletException {
        String apiKey = req.getHeader("X-API-Key");

        if (apiKey == null || apiKey.isBlank()) {
            res.setStatus(401);
            res.setContentType("application/json");
            res.getWriter().write("{\"error\":\"API key required\",\"header\":\"X-API-Key\"}");
            return;
        }

        String merchantId = API_KEYS.get(apiKey);
        if (merchantId == null) {
            res.setStatus(403);
            res.setContentType("application/json");
            res.getWriter().write("{\"error\":\"Invalid API key\"}");
            return;
        }

        // Valid key: set merchantId for downstream use (rate limiter, controllers)
        req.setAttribute(MERCHANT_ID_ATTR, merchantId);
        chain.doFilter(req, res);
    }
}

@SpringBootTest
class ApiKeyFilterTest {
    @Autowired ApiKeyAuthFilter filter;

    @Test void validKey_setsMerchantId() throws Exception {
        var req = new MockHttpServletRequest();
        req.addHeader("X-API-Key", "rzp_live_flipkart_abc123");
        var res = new MockHttpServletResponse();
        filter.doFilter(req, res, (rq,rs)->{}); // empty chain
        assertEquals("MRC-FLIPKART-001", req.getAttribute(ApiKeyAuthFilter.MERCHANT_ID_ATTR));
    }

    @Test void invalidKey_returns403() throws Exception {
        var req = new MockHttpServletRequest();
        req.addHeader("X-API-Key", "invalid-key");
        var res = new MockHttpServletResponse();
        filter.doFilter(req, res, (rq,rs)->{}); // should NOT reach chain
        assertEquals(403, res.getStatus());
    }
}

