import io.micrometer.core.instrument.*;
import io.github.bucket4j.*;
import org.springframework.stereotype.*;
import com.github.benmanes.caffeine.cache.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Duration;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class MetricRateLimiter {
    private final MeterRegistry registry;
    private final LoadingCache<String, Bucket> buckets;

    MetricRateLimiter(MeterRegistry r) {
        registry = r;
        buckets = Caffeine.newBuilder()
            .expireAfterAccess(1, TimeUnit.HOURS)
            .build(key -> Bucket.builder()
                .addLimit(Bandwidth.classic(100, Refill.greedy(100, Duration.ofMinutes(1))))
                .build());
    }

    public boolean isAllowed(String merchantId) {
        Bucket bucket = buckets.get(merchantId);
        boolean allowed = bucket.tryConsume(1);

        if (allowed) {
            Counter.builder("rate.limit.allowed")
                .tag("merchant", merchantId)
                .register(registry)
                .increment();
        } else {
            Counter.builder("rate.limit.exceeded")
                .tag("merchant", merchantId)
                .register(registry)
                .increment();
        }

        // Gauge: current token level (re-register is idempotent in Micrometer)
        Gauge.builder("rate.limit.tokens", bucket, b -> b.getAvailableTokens())
            .tag("merchant", merchantId)
            .register(registry);

        return allowed;
    }
}

@SpringBootTest
class MetricRateLimiterTest {
    @Autowired MetricRateLimiter limiter;
    @Autowired MeterRegistry registry;

    @Test void metrics_incrementOnAllowAndDeny() {
        String merchant = "metric-test-" + System.nanoTime();
        // Drain bucket:
        for (int i = 0; i < 100; i++) limiter.isAllowed(merchant);
        limiter.isAllowed(merchant); // 101st: denied

        double allowed = registry.counter("rate.limit.allowed", "merchant", merchant).count();
        double exceeded = registry.counter("rate.limit.exceeded", "merchant", merchant).count();
        assertEquals(100.0, allowed);
        assertEquals(1.0, exceeded);
    }
}

