@Service
class RzpRateLimiter {
    private final MeterRegistry metrics;
    private final LoadingCache<String, Bucket> buckets;
    RzpRateLimiter(MeterRegistry m){
        metrics=m;
        buckets=Caffeine.newBuilder().expireAfterAccess(1,TimeUnit.HOURS)
            .build(k->Bucket.builder().addLimit(Bandwidth.classic(100,Refill.greedy(100,Duration.ofMinutes(1)))).build());
    }
    boolean tryConsume(String merchant){
        boolean ok=buckets.get(merchant).tryConsume(1);
        if(!ok) Counter.builder("rate.limit.exceeded").tag("merchant",merchant).register(metrics).increment();
        return ok;
    }
    long tokens(String merchant){ return buckets.get(merchant).getAvailableTokens(); }
}

@Component
class RzpRateLimitFilter extends OncePerRequestFilter {
    private final RzpRateLimiter limiter;
    RzpRateLimitFilter(RzpRateLimiter l){limiter=l;}
    @Override protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain)throws IOException,ServletException{
        String merchant=(String)req.getAttribute("merchantId");
        if(merchant==null){chain.doFilter(req,res);return;}
        if(limiter.tryConsume(merchant)){
            res.setHeader("X-RateLimit-Remaining",String.valueOf(limiter.tokens(merchant)));
            chain.doFilter(req,res);
        }else{
            res.setStatus(429);res.setContentType("application/json");
            res.setHeader("Retry-After","60");
            res.getWriter().write("{\"error\":\"rate_limit_exceeded\"}");
        }
    }
}

