    private final Map<String,String> keys=Map.of(
        "key-flipkart","MRC-FLIPKART",
        "key-zomato","MRC-ZOMATO"
    );
    Optional<String> getMerchant(String apiKey){
        return Optional.ofNullable(keys.get(apiKey));
