@Service
class PaymentSecurityChain {
    enum Result {PROCESSED,UNAUTHORIZED,RATE_LIMITED}
    private final ApiKeyStore keys;
    private final LoadingCache<String,Bucket> buckets=Caffeine.newBuilder()
        .expireAfterAccess(1,TimeUnit.HOURS)
        .build(k->Bucket.builder().addLimit(Bandwidth.classic(100,Refill.greedy(100,Duration.ofMinutes(1)))).build());
    PaymentSecurityChain(ApiKeyStore k){keys=k;}

    Result process(String apiKey){
        Optional<String> merchant=keys.getMerchant(apiKey);
        if(merchant.isEmpty()) return Result.UNAUTHORIZED;
        if(!buckets.get(merchant.get()).tryConsume(1)) return Result.RATE_LIMITED;
        return Result.PROCESSED;
    }
}

