@Service class GwApiKeyStore {
    Map<String,String> keys=Map.of("gw-key-rzp","MRC-RZP","gw-key-test","MRC-TEST");
    Optional<String> merchant(String k){return Optional.ofNullable(keys.get(k));}
}

@Service class GwRateLimiter {
    LoadingCache<String,Bucket> b=Caffeine.newBuilder().expireAfterAccess(1,TimeUnit.HOURS)
        .build(k->Bucket.builder().addLimit(Bandwidth.classic(5,Refill.greedy(5,Duration.ofMinutes(1)))).build());
    boolean ok(String m){return b.get(m).tryConsume(1);}
}

@Service class GwIdempotency {
    Cache<String,String> cache=Caffeine.newBuilder().expireAfterWrite(24,TimeUnit.HOURS).build();
    Optional<String> check(String k){return Optional.ofNullable(cache.getIfPresent(k));}
    void mark(String k,String pid){cache.put(k,pid);}
}

@Service class GatewayService {
    private final GwApiKeyStore keys;
    private final GwRateLimiter rl;
    private final GwIdempotency idem;
    enum Result {OK,UNAUTH,RATE_LIMIT,DUPLICATE}
    String lastPaymentId;
    GatewayService(GwApiKeyStore k,GwRateLimiter r,GwIdempotency i){keys=k;rl=r;idem=i;}
    Result process(String apiKey,String idempKey){
        Optional<String> m=keys.merchant(apiKey);
        if(m.isEmpty()) return Result.UNAUTH;
        if(!rl.ok(m.get())) return Result.RATE_LIMIT;
        if(idempKey!=null){
            Optional<String> cached=idem.check(idempKey);
            if(cached.isPresent()){lastPaymentId=cached.get();return Result.DUPLICATE;}
        }
        lastPaymentId="PAY-"+System.nanoTime();
        if(idempKey!=null) idem.mark(idempKey,lastPaymentId);
        return Result.OK;
    }
}

@SpringBootTest
class GatewayTest {
    @Autowired GatewayService gw;
    @Test void validFlow(){assertEquals(GatewayService.Result.OK,gw.process("gw-key-rzp",null));}
    @Test void rateExceeded(){
        for(int i=0;i<5;i++) gw.process("gw-key-test",null);
        assertEquals(GatewayService.Result.RATE_LIMIT,gw.process("gw-key-test",null));
    }
    @Test void duplicateIdempotencyKey(){
        String k="idem-"+UUID.randomUUID();
        assertEquals(GatewayService.Result.OK,gw.process("gw-key-rzp",k));
        assertEquals(GatewayService.Result.DUPLICATE,gw.process("gw-key-rzp",k));
    }
}

