//         expr: increase(api_key_invalid_total{source_ip=~'.+'}[1m]) > 100
//         for: 0m  # immediate
//         labels:
//           severity: critical
//         annotations:
//           summary: 'API key brute force from IP {{ $labels.source_ip }}'

// WHY PROMETHEUS ALERTING (not app code):
// App-level alerting: each pod evaluates independently → duplicate alerts
//   for distributed systems, need to aggregate across all pods.
// Prometheus: aggregates metrics from all pods, evaluates rules centrally.
// 'increase(metric[5m]) > 50': across ALL pods' data combined.
// App code would need distributed coordination (Redis pub/sub) to achieve same.
// Prometheus rule evaluation: every 15s, cheap, no code changes needed.

import io.micrometer.core.instrument.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@org.springframework.context.annotation.Configuration
class RateLimitMetricsConfig {
    @org.springframework.context.annotation.Bean
    RateLimitMetrics rateLimitMetrics(MeterRegistry r){return new RateLimitMetrics(r);}
}

@Service class RateLimitMetrics {
    private final MeterRegistry registry;
    RateLimitMetrics(MeterRegistry r){registry=r;}
    void recordExceeded(String merchant){
        Counter.builder("rate.limit.exceeded").tag("merchant",merchant).register(registry).increment();
    }
    void recordInvalidKey(String sourceIp){
        Counter.builder("api.key.invalid").tag("source_ip",sourceIp).register(registry).increment();
    }
}

@SpringBootTest
class RateLimitAlertMetricTest {
    @Autowired RateLimitMetrics metrics;
    @Autowired MeterRegistry registry;
    @Test void countersIncrement(){
        metrics.recordExceeded("MRC-ALERT-TEST");
        metrics.recordInvalidKey("192.168.1.1");
        assertEquals(1.0,registry.counter("rate.limit.exceeded","merchant","MRC-ALERT-TEST").count());
        assertEquals(1.0,registry.counter("api.key.invalid","source_ip","192.168.1.1").count());
    }
}

import io.github.bucket4j.*;
import io.micrometer.core.instrument.*;
import com.github.benmanes.caffeine.cache.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.time.Duration;
import java.util.concurrent.TimeUnit;

@Service class M23T5RateLimiter {
    private final MeterRegistry m;
    private final LoadingCache<String,Bucket> buckets=Caffeine.newBuilder()
        .expireAfterAccess(1,TimeUnit.HOURS)
        .build(k->Bucket.builder().addLimit(Bandwidth.classic(5,Refill.greedy(5,Duration.ofMinutes(1)))).build());
    M23T5RateLimiter(MeterRegistry m){this.m=m;}
    boolean allow(String merchant){
        boolean ok=buckets.get(merchant).tryConsume(1);
        if(!ok) Counter.builder("rate.limit.exceeded").tag("merchant",merchant).register(m).increment();
        return ok;
    }
}

@Service class M23T5Idempotency {
    private final Cache<String,String> cache=Caffeine.newBuilder().expireAfterWrite(24,TimeUnit.HOURS).build();
    Optional<String> check(String k){return Optional.ofNullable(cache.getIfPresent(k));}
    void mark(String k,String v){cache.put(k,v);}
}

@SpringBootTest
class M23T5SynthesisTest {
    @Autowired M23T5RateLimiter rl;
    @Autowired M23T5Idempotency idem;
    @Autowired MeterRegistry registry;

    @Test void firstRequest_allowed(){assertTrue(rl.allow("MRC-SYNTH-1"));}
    @Test void bucketExhausted_denied(){
        String m="MRC-EXHAUST-SYNTH-"+System.nanoTime();
        for(int i=0;i<5;i++) rl.allow(m);
        assertFalse(rl.allow(m));
    }
    @Test void idempotency_deduplicates(){
        String k="IDEM-"+UUID.randomUUID();
        idem.mark(k,"PAY-001");
        assertEquals(Optional.of("PAY-001"),idem.check(k));
        assertEquals(Optional.of("PAY-001"),idem.check(k)); // same result
    }
    @Test void metric_incrementsOnDeny(){
        String m="MRC-METRIC-SYNTH-"+System.nanoTime();
        for(int i=0;i<5;i++) rl.allow(m);
        rl.allow(m);
        assertEquals(1.0,registry.counter("rate.limit.exceeded","merchant",m).count());
    }
}
